435	// Cost computes bead and feature cost attribution.
436	func (s *Service) Cost(query Query) (CostReport, error) {
437		beads, sessions, sessionByID, sessionCostPresent, err := s.loadInputs()
438		if err != nil {
439			return CostReport{}, err
440		}
441		_ = sessions
442	
443		selected := selectBeads(beads, query.BeadID, query.FeatureID)
444		rows := make([]BeadCostRow, 0, len(selected))
445		for _, b := range selected {
446			row := buildBeadCostRow(b, sessions, sessionByID, sessionCostPresent, query)
447			rows = append(rows, row)
448		}
449		sort.Slice(rows, func(i, j int) bool {
450			return rows[i].BeadID < rows[j].BeadID
451		})
452	
453		featureRows := buildFeatureCostRows(rows)
454	
455		report := CostReport{
456			Scope:     costScope(query),
457			Window:    windowForQuery(query),
458			BeadID:    query.BeadID,
459			FeatureID: query.FeatureID,
460			Beads:     rows,
461			Features:  featureRows,
462		}
463	
464		for _, row := range rows {
465			report.Summary.Beads++
466			switch row.CostState {
467			case stateKnown:
468				if row.CostUSD != nil {
469					report.Summary.KnownCostUSD += *row.CostUSD
470				}
471			case stateEstimated:
472				if row.CostUSD != nil {
473					report.Summary.EstimatedCostUSD += *row.CostUSD
474				}
475			default:
476				report.Summary.UnknownBeads++
477			}
478		}
479		report.Summary.Features = len(featureRows)
480		return report, nil
481	}
