559			if query.HasSince && row.FirstClosedAt != nil && row.FirstClosedAt.Before(query.Since) {
560				continue
561			}
562			rows = append(rows, row)
563		}
564		sort.Slice(rows, func(i, j int) bool {
565			if rows[i].FirstClosedAt == nil && rows[j].FirstClosedAt == nil {
566				return rows[i].BeadID < rows[j].BeadID
567			}
568			if rows[i].FirstClosedAt == nil {
569				return false
570			}
571			if rows[j].FirstClosedAt == nil {
572				return true
573			}
574			if !rows[i].FirstClosedAt.Equal(*rows[j].FirstClosedAt) {
575				return rows[i].FirstClosedAt.Before(*rows[j].FirstClosedAt)
576			}
577			return rows[i].BeadID < rows[j].BeadID
578		})
