616	func windowForQuery(query Query) Window {
617		if !query.HasSince || query.Since.IsZero() {
618			return Window{}
619		}
620		since := query.Since.UTC()
621		return Window{
622			Since: &since,
623			Label: since.Format(time.RFC3339),
624		}
625	}
