693	func (r *sessionLoadRecord) UnmarshalJSON(data []byte) error {
694		type sessionAlias agent.SessionEntry
695	
696		var entry sessionAlias
697		if err := json.Unmarshal(data, &entry); err != nil {
698			return err
699		}
700		r.Entry = agent.SessionEntry(entry)
701	
702		var raw map[string]json.RawMessage
703		if err := json.Unmarshal(data, &raw); err != nil {
704			return err
705		}
706		_, r.CostUSDPresent = raw["cost_usd"]
707		return nil
