772	func selectBeads(beads []bead.Bead, beadID, featureID string) []bead.Bead {
773		if beadID != "" {
774			for _, b := range beads {
775				if b.ID == beadID {
776					return []bead.Bead{b}
777				}
778			}
779			return []bead.Bead{}
780		}
781		if featureID == "" {
782			return beads
783		}
784		out := make([]bead.Bead, 0, len(beads))
785		for _, b := range beads {
786			if extraString(b, "spec-id", "spec_id") == featureID {
787				out = append(out, b)
788			}
789		}
790		return out
791	}
792	
793	func buildBeadCostRow(b bead.Bead, sessions []agent.SessionEntry, sessionByID map[string]agent.SessionEntry, sessionCostPresent map[string]bool, query Query) BeadCostRow {
794		matches := matchedSessionsForBead(b, sessions, sessionByID)
795		if query.HasSince {
796			filtered := matches[:0]
797			for _, sess := range matches {
798				if sess.Timestamp.Before(query.Since) {
799					continue
800				}
801				filtered = append(filtered, sess)
802			}
803			matches = filtered
804		}
805	
806		row := BeadCostRow{
807			BeadID:     b.ID,
808			Title:      b.Title,
809			SpecID:     extraString(b, "spec-id", "spec_id"),
810			Status:     b.Status,
811			SessionIDs: make([]string, 0, len(matches)),
812			Provenance: make([]SourceRef, 0, len(matches)),
813		}
814	
815		var costTotal float64
816		var knownCount, estimatedCount, unknownCount int
817		for _, sess := range matches {
818			explicitCost := sessionCostPresent[sess.ID]
819			row.SessionIDs = append(row.SessionIDs, sess.ID)
820			row.InputTokens += sessionInputTokens(sess)
821			row.OutputTokens += sessionOutputTokens(sess)
822			row.TotalTokens += sessionTotalTokens(sess)
823	
824			if cost := sessionDerivedCost(sess, explicitCost); cost != nil {
825				costTotal += *cost
826				if sessionCostState(sess, explicitCost) == stateKnown {
827					knownCount++
828				} else {
829					estimatedCount++
830				}
831			} else {
832				unknownCount++
833			}
834	
835			row.Provenance = append(row.Provenance, sourceRefForSession(b.ID, sess))
836		}
837	
838		switch {
839		case len(matches) == 0:
840			row.CostState = stateUnknown
841		case unknownCount > 0 && knownCount == 0 && estimatedCount == 0:
842			row.CostState = stateUnknown
843		case estimatedCount > 0:
844			row.CostState = stateEstimated
845		default:
846			row.CostState = stateKnown
847		}
848		if row.CostState != stateUnknown {
849			row.CostUSD = float64Ptr(costTotal)
850		}
851		row.UnknownSessions = unknownCount
852		return row
853	}
854	
855	func buildFeatureCostRows(beadRows []BeadCostRow) []FeatureCostRow {
856		grouped := make(map[string]*FeatureCostRow)
857		for _, row := range beadRows {
858			if row.SpecID == "" {
859				continue
860			}
861			entry, ok := grouped[row.SpecID]
862			if !ok {
863				entry = &FeatureCostRow{SpecID: row.SpecID}
864				grouped[row.SpecID] = entry
865			}
866			entry.BeadIDs = append(entry.BeadIDs, row.BeadID)
867			entry.InputTokens += row.InputTokens
868			entry.OutputTokens += row.OutputTokens
869			entry.TotalTokens += row.TotalTokens
870			if row.CostState == stateUnknown || row.CostUSD == nil {
871				entry.UnknownBeads++
872				continue
873			}
874			switch row.CostState {
875			case stateKnown:
876				if entry.CostUSD == nil {
877					entry.CostUSD = float64Ptr(0)
878				}
879			case stateEstimated:
880				if entry.CostState == stateKnown {
881					entry.CostState = stateEstimated
882				}
883			}
884			if entry.CostUSD == nil {
885				entry.CostUSD = float64Ptr(0)
886			}
887			*entry.CostUSD += *row.CostUSD
888			if row.CostState == stateEstimated {
889				entry.CostState = stateEstimated
890			} else if entry.CostState == "" {
891				entry.CostState = stateKnown
892			}
893		}
894	
895		out := make([]FeatureCostRow, 0, len(grouped))
896		for _, row := range grouped {
897			sort.Strings(row.BeadIDs)
898			if row.CostUSD != nil {
899				if row.CostState == "" {
900					row.CostState = stateKnown
901				}
902			} else {
903				row.CostState = stateUnknown
904			}
905			out = append(out, *row)
906		}
907		sort.Slice(out, func(i, j int) bool {
908			return out[i].SpecID < out[j].SpecID
909		})
910		return out
