1203	func commitTimeWithWorkingDir(workingDir, sha string) (time.Time, bool) {
1204		if sha == "" {
1205			return time.Time{}, false
1206		}
1207		cmd := internalgit.Command(context.Background(), workingDir, "show", "-s", "--format=%cI", sha)
1208		out, err := cmd.Output()
1209		if err != nil {
1210			return time.Time{}, false
1211		}
1212		parsed, err := time.Parse(time.RFC3339, strings.TrimSpace(string(out)))
1213		if err != nil {
1214			return time.Time{}, false
1215		}
1216		return parsed.UTC(), true
1217	}
