1366	func statusFromEventToken(raw string) (string, bool) {
1367		normalized := normalizeToken(raw)
1368		if status, ok := statusFromToken(normalized); ok {
1369			return status, true
1370		}
1371		for _, prefix := range []string{"status", "state", "transition"} {
1372			for _, marker := range []string{prefix + ":", prefix + "=", prefix + "_"} {
1373				if strings.HasPrefix(normalized, marker) {
1374					return statusFromToken(strings.TrimLeft(strings.TrimPrefix(normalized, marker), "_:="))
1375				}
1376			}
1377		}
1378		return "", false
1379	}
