1381	func statusFromToken(raw string) (string, bool) {
1382		switch normalizeToken(raw) {
1383		case "proposed", "proposal":
1384			return bead.StatusProposed, true
1385		case "open", "opened":
1386			return bead.StatusOpen, true
1387		case "in_progress", "inprogress", "started", "start", "working":
1388			return bead.StatusInProgress, true
1389		case "blocked", "block":
1390			return bead.StatusBlocked, true
1391		case "closed", "close", "finished", "done":
1392			return bead.StatusClosed, true
1393		case "cancelled", "canceled", "cancel":
1394			return bead.StatusCancelled, true
1395		case "reopened", "reopen":
1396			return bead.StatusOpen, true
1397		default:
1398			return "", false
1399		}
1400	}
