1417	func parsePositiveInt(raw string) (int, error) {
1418		raw = strings.TrimSpace(raw)
1419		if raw == "" {
1420			return 0, fmt.Errorf("empty")
1421		}
1422		n := 0
1423		for _, r := range raw {
1424			if r < '0' || r > '9' {
1425				return 0, fmt.Errorf("invalid")
1426			}
1427			n = n*10 + int(r-'0')
1428		}
1429		return n, nil
1430	}
