package cmd

import (
	"encoding/csv"
	"encoding/json"
	"fmt"
	"math"
	"sort"
	"strconv"
	"strings"
	"text/tabwriter"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
	"github.com/spf13/cobra"
)

// newWorkMetricsAnalyzeCommand returns "ddx work metrics analyze".
func (f *CommandFactory) newWorkMetricsAnalyzeCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "analyze",
		Short: "Query cross-attempt performance metrics",
		Long: `analyze reads .ddx/metrics/attempts.jsonl and prints aggregated metrics
grouped by one or more dimensions.

Dimensions (--by, comma-separated):
  model, harness, profile, prompt_template_hash, spec_id, outcome,
  bead_id, day, week, month

Aggregations (columns):
  count, success_rate, avg_cost_usd, sum_cost_usd,
  p50_duration_ms, p95_duration_ms,
  avg_input_tokens, avg_output_tokens,
  review_block_rate, escalation_rate`,
		Example: `  # Aggregate by model
  ddx work metrics analyze --by model

  # Aggregate by model and outcome
  ddx work metrics analyze --by model,outcome

  # Recent week, by spec
  ddx work metrics analyze --by spec_id --since 7d

  # Drill into one model
  ddx work metrics analyze --where model=claude-sonnet-4-6 --by prompt_template_hash

  # Machine-readable output
  ddx work metrics analyze --by model --json`,
		Args: cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			projectFlag, _ := cmd.Flags().GetString("project")
			projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)

			byFlag, _ := cmd.Flags().GetString("by")
			sinceFlag, _ := cmd.Flags().GetString("since")
			whereFlags, _ := cmd.Flags().GetStringArray("where")
			asJSON, _ := cmd.Flags().GetBool("json")
			asCSV, _ := cmd.Flags().GetBool("csv")

			dims, err := parseAnalyzeDims(byFlag)
			if err != nil {
				return err
			}

			var sinceTime time.Time
			if sinceFlag != "" {
				d, err := parseRelDuration(sinceFlag)
				if err != nil {
					return fmt.Errorf("--since: %w", err)
				}
				sinceTime = time.Now().UTC().Add(-d)
			}

			whereFilters, err := parseWhereFilters(whereFlags)
			if err != nil {
				return fmt.Errorf("--where: %w", err)
			}

			rows, err := attemptmetrics.LoadRows(projectRoot)
			if err != nil {
				return fmt.Errorf("load metrics: %w", err)
			}

			rows = applyAnalyzeFilters(rows, sinceTime, whereFilters)
			result := aggregateAnalyzeRows(rows, dims)

			out := cmd.OutOrStdout()
			switch {
			case asJSON:
				return printAnalyzeJSON(out, result, dims)
			case asCSV:
				return printAnalyzeCSV(out, result, dims)
			default:
				return printAnalyzeTable(out, result, dims)
			}
		},
	}

	cmd.Flags().String("project", "", "Target project root path or name (default: CWD git root)")
	cmd.Flags().String("by", "model", "Comma-separated list of dimensions to group by")
	cmd.Flags().String("since", "", "Only include attempts started within this duration (e.g. 7d, 2w, 30d)")
	cmd.Flags().StringArray("where", nil, "Filter: key=value (repeatable)")
	cmd.Flags().Bool("json", false, "Emit JSONL rows instead of a table")
	cmd.Flags().Bool("csv", false, "Emit CSV instead of a table")
	return cmd
}

// analyzeGroup accumulates per-group statistics.
type analyzeGroup struct {
	dimValues []string // parallel to dims slice
	count     int
	success   int      // outcome == "closed-merged"
	costTotal float64
	durations []int
	inputTok  int64
	outputTok int64
	blocks    int // ReviewVerdict == "BLOCK"
	escalated int // LadderStepsTaken > 0
}

// analyzeResult is one output row.
type analyzeResult struct {
	DimValues      []string
	Count          int
	SuccessRate    float64
	AvgCostUSD     float64
	SumCostUSD     float64
	P50DurationMS  int
	P95DurationMS  int
	AvgInputTokens float64
	AvgOutputTokens float64
	ReviewBlockRate float64
	EscalationRate  float64
}

func parseAnalyzeDims(byFlag string) ([]string, error) {
	if byFlag == "" {
		return nil, fmt.Errorf("--by is required")
	}
	parts := strings.Split(byFlag, ",")
	dims := make([]string, 0, len(parts))
	for _, p := range parts {
		d := strings.TrimSpace(p)
		if d == "" {
			continue
		}
		if !validAnalyzeDim(d) {
			return nil, fmt.Errorf("unknown dimension %q; valid: model, harness, profile, prompt_template_hash, spec_id, outcome, bead_id, day, week, month", d)
		}
		dims = append(dims, d)
	}
	if len(dims) == 0 {
		return nil, fmt.Errorf("--by: at least one dimension required")
	}
	return dims, nil
}

func validAnalyzeDim(d string) bool {
	switch d {
	case "model", "harness", "profile", "prompt_template_hash",
		"spec_id", "outcome", "bead_id", "day", "week", "month":
		return true
	}
	return false
}

// parseRelDuration extends time.ParseDuration with d (days), w (weeks), mo (months).
func parseRelDuration(s string) (time.Duration, error) {
	s = strings.TrimSpace(s)
	if strings.HasSuffix(s, "mo") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "mo"))
		if err != nil || n <= 0 {
			return 0, fmt.Errorf("invalid duration %q", s)
		}
		return time.Duration(n) * 30 * 24 * time.Hour, nil
	}
	if strings.HasSuffix(s, "w") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "w"))
		if err != nil || n <= 0 {
			return 0, fmt.Errorf("invalid duration %q", s)
		}
		return time.Duration(n) * 7 * 24 * time.Hour, nil
	}
	if strings.HasSuffix(s, "d") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
		if err != nil || n <= 0 {
			return 0, fmt.Errorf("invalid duration %q", s)
		}
		return time.Duration(n) * 24 * time.Hour, nil
	}
	return time.ParseDuration(s)
}

// parseWhereFilters parses --where key=value entries into a map.
func parseWhereFilters(entries []string) (map[string]string, error) {
	out := make(map[string]string, len(entries))
	for _, e := range entries {
		idx := strings.IndexByte(e, '=')
		if idx <= 0 {
			return nil, fmt.Errorf("invalid filter %q: expected key=value", e)
		}
		k := e[:idx]
		v := e[idx+1:]
		if !validAnalyzeDim(k) {
			return nil, fmt.Errorf("unknown filter key %q", k)
		}
		out[k] = v
	}
	return out, nil
}

// dimValue extracts the dimension value for dim from row.
func dimValue(row attemptmetrics.AttemptRow, dim string) string {
	switch dim {
	case "model":
		return row.Model
	case "harness":
		return row.Harness
	case "profile":
		return row.Profile
	case "prompt_template_hash":
		return row.PromptTemplateHash
	case "spec_id":
		return row.SpecID
	case "outcome":
		return row.Outcome
	case "bead_id":
		return row.BeadID
	case "day":
		return timeBucket(row.TSStart, "2006-01-02")
	case "week":
		return weekBucket(row.TSStart)
	case "month":
		return timeBucket(row.TSStart, "2006-01")
	}
	return ""
}

func timeBucket(ts, layout string) string {
	if ts == "" {
		return ""
	}
	t, err := time.Parse(time.RFC3339, ts)
	if err != nil {
		return ""
	}
	return t.UTC().Format(layout)
}

func weekBucket(ts string) string {
	if ts == "" {
		return ""
	}
	t, err := time.Parse(time.RFC3339, ts)
	if err != nil {
		return ""
	}
	year, week := t.UTC().ISOWeek()
	return fmt.Sprintf("%04d-W%02d", year, week)
}

// applyAnalyzeFilters filters rows by since time and where key=value constraints.
func applyAnalyzeFilters(rows []attemptmetrics.AttemptRow, since time.Time, where map[string]string) []attemptmetrics.AttemptRow {
	if since.IsZero() && len(where) == 0 {
		return rows
	}
	out := rows[:0:0]
	for _, r := range rows {
		if !since.IsZero() {
			if r.TSStart == "" {
				continue
			}
			t, err := time.Parse(time.RFC3339, r.TSStart)
			if err != nil || t.Before(since) {
				continue
			}
		}
		skip := false
		for k, v := range where {
			if dimValue(r, k) != v {
				skip = true
				break
			}
		}
		if !skip {
			out = append(out, r)
		}
	}
	return out
}

// aggregateAnalyzeRows groups rows by dims and computes statistics.
func aggregateAnalyzeRows(rows []attemptmetrics.AttemptRow, dims []string) []analyzeResult {
	groups := make(map[string]*analyzeGroup)
	keys := make([]string, 0)

	for _, r := range rows {
		vals := make([]string, len(dims))
		for i, d := range dims {
			vals[i] = dimValue(r, d)
		}
		key := strings.Join(vals, "\x00")
		g, ok := groups[key]
		if !ok {
			g = &analyzeGroup{dimValues: vals}
			groups[key] = g
			keys = append(keys, key)
		}
		g.count++
		if r.Outcome == "closed-merged" {
			g.success++
		}
		g.costTotal += r.CostUSD
		if r.DurationMS > 0 {
			g.durations = append(g.durations, r.DurationMS)
		}
		g.inputTok += int64(r.InputTokens)
		g.outputTok += int64(r.OutputTokens)
		if strings.EqualFold(r.ReviewVerdict, "BLOCK") {
			g.blocks++
		}
		if r.LadderStepsTaken > 0 {
			g.escalated++
		}
	}

	sort.Strings(keys)

	results := make([]analyzeResult, 0, len(keys))
	for _, key := range keys {
		g := groups[key]
		sort.Ints(g.durations)
		n := g.count
		res := analyzeResult{
			DimValues:  g.dimValues,
			Count:      n,
			SumCostUSD: g.costTotal,
		}
		if n > 0 {
			res.SuccessRate = float64(g.success) / float64(n)
			res.AvgCostUSD = g.costTotal / float64(n)
			res.ReviewBlockRate = float64(g.blocks) / float64(n)
			res.EscalationRate = float64(g.escalated) / float64(n)
			res.AvgInputTokens = float64(g.inputTok) / float64(n)
			res.AvgOutputTokens = float64(g.outputTok) / float64(n)
			res.P50DurationMS = percentileInt(g.durations, 50)
			res.P95DurationMS = percentileInt(g.durations, 95)
		}
		results = append(results, res)
	}
	return results
}

func percentileInt(sorted []int, p float64) int {
	n := len(sorted)
	if n == 0 {
		return 0
	}
	idx := int(math.Ceil(p/100.0*float64(n))) - 1
	if idx < 0 {
		idx = 0
	}
	if idx >= n {
		idx = n - 1
	}
	return sorted[idx]
}

// analyzeResultMap converts an analyzeResult to a map for JSON/CSV output.
func analyzeResultMap(res analyzeResult, dims []string) map[string]any {
	m := make(map[string]any, len(dims)+10)
	for i, d := range dims {
		m[d] = res.DimValues[i]
	}
	m["count"] = res.Count
	m["success_rate"] = res.SuccessRate
	m["avg_cost_usd"] = res.AvgCostUSD
	m["sum_cost_usd"] = res.SumCostUSD
	m["p50_duration_ms"] = res.P50DurationMS
	m["p95_duration_ms"] = res.P95DurationMS
	m["avg_input_tokens"] = res.AvgInputTokens
	m["avg_output_tokens"] = res.AvgOutputTokens
	m["review_block_rate"] = res.ReviewBlockRate
	m["escalation_rate"] = res.EscalationRate
	return m
}

func analyzeCSVHeader(dims []string) []string {
	cols := make([]string, 0, len(dims)+10)
	cols = append(cols, dims...)
	cols = append(cols,
		"count",
		"success_rate",
		"avg_cost_usd",
		"sum_cost_usd",
		"p50_duration_ms",
		"p95_duration_ms",
		"avg_input_tokens",
		"avg_output_tokens",
		"review_block_rate",
		"escalation_rate",
	)
	return cols
}

func analyzeCSVRow(res analyzeResult, dims []string) []string {
	row := make([]string, 0, len(dims)+10)
	row = append(row, res.DimValues...)
	row = append(row,
		strconv.Itoa(res.Count),
		fmt.Sprintf("%.4f", res.SuccessRate),
		fmt.Sprintf("%.6f", res.AvgCostUSD),
		fmt.Sprintf("%.6f", res.SumCostUSD),
		strconv.Itoa(res.P50DurationMS),
		strconv.Itoa(res.P95DurationMS),
		fmt.Sprintf("%.2f", res.AvgInputTokens),
		fmt.Sprintf("%.2f", res.AvgOutputTokens),
		fmt.Sprintf("%.4f", res.ReviewBlockRate),
		fmt.Sprintf("%.4f", res.EscalationRate),
	)
	return row
}

func printAnalyzeJSON(out interface{ Write([]byte) (int, error) }, results []analyzeResult, dims []string) error {
	enc := json.NewEncoder(out.(interface {
		Write([]byte) (int, error)
	}))
	for _, res := range results {
		if err := enc.Encode(analyzeResultMap(res, dims)); err != nil {
			return err
		}
	}
	return nil
}

func printAnalyzeCSV(out interface{ Write([]byte) (int, error) }, results []analyzeResult, dims []string) error {
	w := csv.NewWriter(out.(interface{ Write([]byte) (int, error) }))
	if err := w.Write(analyzeCSVHeader(dims)); err != nil {
		return err
	}
	for _, res := range results {
		if err := w.Write(analyzeCSVRow(res, dims)); err != nil {
			return err
		}
	}
	w.Flush()
	return w.Error()
}

func printAnalyzeTable(out interface{ Write([]byte) (int, error) }, results []analyzeResult, dims []string) error {
	if len(results) == 0 {
		_, err := fmt.Fprintln(out.(interface{ Write([]byte) (int, error) }), "no data")
		return err
	}

	tw := tabwriter.NewWriter(out.(interface{ Write([]byte) (int, error) }), 0, 0, 2, ' ', 0)
	header := strings.Join(append(dims, "COUNT", "SUCCESS%", "AVG_COST", "SUM_COST", "P50_MS", "P95_MS", "AVG_IN_TOK", "AVG_OUT_TOK", "BLOCK%", "ESC%"), "\t")
	fmt.Fprintln(tw, header)

	sep := make([]string, len(dims)+10)
	for i := range sep {
		sep[i] = "---"
	}
	fmt.Fprintln(tw, strings.Join(sep, "\t"))

	for _, res := range results {
		cols := make([]string, 0, len(dims)+10)
		for _, v := range res.DimValues {
			if v == "" {
				v = "-"
			}
			cols = append(cols, v)
		}
		cols = append(cols,
			strconv.Itoa(res.Count),
			fmt.Sprintf("%.1f%%", res.SuccessRate*100),
			fmt.Sprintf("$%.4f", res.AvgCostUSD),
			fmt.Sprintf("$%.4f", res.SumCostUSD),
			strconv.Itoa(res.P50DurationMS),
			strconv.Itoa(res.P95DurationMS),
			fmt.Sprintf("%.0f", res.AvgInputTokens),
			fmt.Sprintf("%.0f", res.AvgOutputTokens),
			fmt.Sprintf("%.1f%%", res.ReviewBlockRate*100),
			fmt.Sprintf("%.1f%%", res.EscalationRate*100),
		)
		fmt.Fprintln(tw, strings.Join(cols, "\t"))
	}
	return tw.Flush()
}

