package cmd

import (
	"bytes"
	"encoding/csv"
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
)

// writeAttemptRows writes rows to .ddx/metrics/attempts.jsonl in dir and
// returns dir as the project root.
func writeAttemptRows(t *testing.T, rows []attemptmetrics.AttemptRow) string {
	t.Helper()
	dir := t.TempDir()
	metricsDir := filepath.Join(dir, ".ddx", "metrics")
	if err := os.MkdirAll(metricsDir, 0o755); err != nil {
		t.Fatalf("mkdir metrics: %v", err)
	}
	for _, r := range rows {
		if err := attemptmetrics.AppendRow(dir, r); err != nil {
			t.Fatalf("AppendRow: %v", err)
		}
	}
	return dir
}

// runAnalyze executes "ddx work metrics analyze <args>" and returns stdout.
func runAnalyze(t *testing.T, dir string, extraArgs ...string) string {
	t.Helper()
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	var out bytes.Buffer
	f := &CommandFactory{WorkingDir: dir}
	cmd := f.newWorkMetricsCommand()
	cmd.SetOut(&out)
	cmd.SetErr(&out)
	args := append([]string{"analyze", "--project", dir}, extraArgs...)
	cmd.SetArgs(args)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("analyze command failed: %v\noutput: %s", err, out.String())
	}
	return out.String()
}

func ts(offset time.Duration) string {
	base := time.Date(2026, 1, 10, 12, 0, 0, 0, time.UTC)
	return base.Add(offset).Format(time.RFC3339)
}

func TestAnalyze_ByModel(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "sonnet", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, InputTokens: 1000, OutputTokens: 500, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "sonnet", Outcome: "closed-merged", CostUSD: 2.0, DurationMS: 90000, InputTokens: 2000, OutputTokens: 1000, TSStart: ts(time.Hour)},
		{SchemaVersion: 1, AttemptID: "a3", BeadID: "b3", Model: "haiku", Outcome: "task_failed", CostUSD: 0.5, DurationMS: 30000, InputTokens: 500, OutputTokens: 200, TSStart: ts(2 * time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "model")

	if !strings.Contains(out, "sonnet") {
		t.Errorf("expected 'sonnet' in output:\n%s", out)
	}
	if !strings.Contains(out, "haiku") {
		t.Errorf("expected 'haiku' in output:\n%s", out)
	}
	// sonnet has 2 rows, haiku has 1
	if !strings.Contains(out, "2") {
		t.Errorf("expected count 2 for sonnet:\n%s", out)
	}
}

func TestAnalyze_BySpecId(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", SpecID: "FEAT-010", Model: "sonnet", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", SpecID: "FEAT-010", Model: "sonnet", Outcome: "task_failed", CostUSD: 0.5, DurationMS: 30000, TSStart: ts(time.Hour)},
		{SchemaVersion: 1, AttemptID: "a3", BeadID: "b3", SpecID: "FEAT-020", Model: "sonnet", Outcome: "closed-merged", CostUSD: 2.0, DurationMS: 90000, TSStart: ts(2 * time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "spec_id")

	if !strings.Contains(out, "FEAT-010") {
		t.Errorf("expected 'FEAT-010' in output:\n%s", out)
	}
	if !strings.Contains(out, "FEAT-020") {
		t.Errorf("expected 'FEAT-020' in output:\n%s", out)
	}
}

func TestAnalyze_ComposedDimensions(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "sonnet", Harness: "claude", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "sonnet", Harness: "agent", Outcome: "task_failed", CostUSD: 0.5, DurationMS: 30000, TSStart: ts(time.Hour)},
		{SchemaVersion: 1, AttemptID: "a3", BeadID: "b3", Model: "haiku", Harness: "claude", Outcome: "closed-merged", CostUSD: 0.3, DurationMS: 20000, TSStart: ts(2 * time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "model,harness")

	// All three combinations should appear
	if !strings.Contains(out, "sonnet") {
		t.Errorf("expected 'sonnet':\n%s", out)
	}
	if !strings.Contains(out, "claude") {
		t.Errorf("expected 'claude':\n%s", out)
	}
	if !strings.Contains(out, "agent") {
		t.Errorf("expected 'agent':\n%s", out)
	}
	if !strings.Contains(out, "haiku") {
		t.Errorf("expected 'haiku':\n%s", out)
	}
}

func TestAnalyze_SinceFilter(t *testing.T) {
	now := time.Now().UTC()
	old := now.Add(-10 * 24 * time.Hour).Format(time.RFC3339)  // 10 days ago
	recent := now.Add(-1 * time.Hour).Format(time.RFC3339)     // 1 hour ago

	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "old-model", Outcome: "closed-merged", CostUSD: 5.0, DurationMS: 60000, TSStart: old},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "recent-model", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 30000, TSStart: recent},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "model", "--since", "7d")

	if strings.Contains(out, "old-model") {
		t.Errorf("old-model should be filtered out by --since 7d:\n%s", out)
	}
	if !strings.Contains(out, "recent-model") {
		t.Errorf("expected 'recent-model' in output:\n%s", out)
	}
}

func TestAnalyze_WhereFilter(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "sonnet", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "haiku", Outcome: "task_failed", CostUSD: 0.2, DurationMS: 10000, TSStart: ts(time.Hour)},
		{SchemaVersion: 1, AttemptID: "a3", BeadID: "b3", Model: "sonnet", Outcome: "task_failed", CostUSD: 0.8, DurationMS: 45000, TSStart: ts(2 * time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "outcome", "--where", "model=sonnet")

	// Only sonnet rows should be aggregated
	if strings.Contains(out, "haiku") {
		t.Errorf("haiku should be filtered out by --where model=sonnet:\n%s", out)
	}
	// Should have 2 rows: closed-merged and task_failed for sonnet
	if !strings.Contains(out, "closed-merged") {
		t.Errorf("expected 'closed-merged' outcome:\n%s", out)
	}
	if !strings.Contains(out, "task_failed") {
		t.Errorf("expected 'task_failed' outcome:\n%s", out)
	}
}

func TestAnalyze_JSONOutput(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "sonnet", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, InputTokens: 1000, OutputTokens: 500, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "haiku", Outcome: "task_failed", CostUSD: 0.2, DurationMS: 20000, InputTokens: 200, OutputTokens: 100, TSStart: ts(time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "model", "--json")

	lines := strings.Split(strings.TrimSpace(out), "\n")
	if len(lines) != 2 {
		t.Fatalf("expected 2 JSONL lines, got %d:\n%s", len(lines), out)
	}
	for _, line := range lines {
		var m map[string]any
		if err := json.Unmarshal([]byte(line), &m); err != nil {
			t.Errorf("invalid JSON line: %v\nline: %s", err, line)
			continue
		}
		if _, ok := m["model"]; !ok {
			t.Errorf("missing 'model' key in JSON: %s", line)
		}
		if _, ok := m["count"]; !ok {
			t.Errorf("missing 'count' key in JSON: %s", line)
		}
		if _, ok := m["success_rate"]; !ok {
			t.Errorf("missing 'success_rate' key in JSON: %s", line)
		}
		if _, ok := m["avg_cost_usd"]; !ok {
			t.Errorf("missing 'avg_cost_usd' key in JSON: %s", line)
		}
	}
}

func TestAnalyze_CSVOutput(t *testing.T) {
	rows := []attemptmetrics.AttemptRow{
		{SchemaVersion: 1, AttemptID: "a1", BeadID: "b1", Model: "sonnet", Outcome: "closed-merged", CostUSD: 1.0, DurationMS: 60000, InputTokens: 1000, OutputTokens: 500, TSStart: ts(0)},
		{SchemaVersion: 1, AttemptID: "a2", BeadID: "b2", Model: "haiku", Outcome: "task_failed", CostUSD: 0.2, DurationMS: 20000, InputTokens: 200, OutputTokens: 100, TSStart: ts(time.Hour)},
	}
	dir := writeAttemptRows(t, rows)
	out := runAnalyze(t, dir, "--by", "model", "--csv")

	r := csv.NewReader(strings.NewReader(out))
	records, err := r.ReadAll()
	if err != nil {
		t.Fatalf("invalid CSV: %v\noutput:\n%s", err, out)
	}
	if len(records) < 2 {
		t.Fatalf("expected at least header + 1 data row, got %d records", len(records))
	}
	header := records[0]
	if header[0] != "model" {
		t.Errorf("first CSV column should be 'model', got %q", header[0])
	}
	// Verify count column exists
	found := false
	for _, h := range header {
		if h == "count" {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("CSV header missing 'count' column: %v", header)
	}
	// Two data rows (one per model)
	if len(records) != 3 {
		t.Errorf("expected 3 CSV records (header + 2 models), got %d", len(records))
	}
}
